$offers$::jsonb) AS offer(
    part_public_id TEXT,
    search_query TEXT,
    title TEXT,
    offer_url TEXT,
    low_price INTEGER,
    raw_payload JSONB
  )
), upsert_offers AS (
  INSERT INTO part_external_offers (
    part_id, source, search_query, title, image_url, supplier_name, offer_url, low_price, raw_payload, refreshed_at, updated_at
  )
  SELECT p.id,
         'DANAWA_BACKUP',
         o.search_query,
         o.title,
         NULL,
         'Danawa',
         o.offer_url,
         o.low_price,
         o.raw_payload,
         now(),
         now()
  FROM manual_offers o
  JOIN parts p ON p.public_id::text = o.part_public_id
  ON CONFLICT (part_id, source) WHERE deleted_at IS NULL
  DO UPDATE SET search_query = EXCLUDED.search_query,
                title = EXCLUDED.title,
                supplier_name = EXCLUDED.supplier_name,
                offer_url = EXCLUDED.offer_url,
                low_price = EXCLUDED.low_price,
                raw_payload = EXCLUDED.raw_payload,
                refreshed_at = EXCLUDED.refreshed_at,
                updated_at = EXCLUDED.updated_at
  RETURNING part_id
), trend_seed AS (
  SELECT *
  FROM jsonb_to_recordset($trend$
